parameters.jsonBody:
={
  "trigger_id": "{{ $json.trigger_id }}",
  "view": {
    "type": "modal",
    "callback_id": "customer_feedback",
    "private_metadata": "{{ JSON.stringify({channel_id: $json.channel_id, user_id: $json.user_id, user_name: $json.user_name}) }}",
    "title": { "type": "plain_text", "text": "💬 顧客フィードバック" },
    "submit": { "type": "plain_text", "text": "送信" },
    "close": { "type": "plain_text", "text": "閉じる" },
    "blocks": [
      {
        "type": "input", "block_id": "deal_code",
        "label": { "type": "plain_text", "text": "案件 ID" },
        "element": { "type": "plain_text_input", "action_id": "value", "placeholder": { "type": "plain_text", "text": "DEAL-2026-00000" } }
      },
      {
        "type": "input", "block_id": "customer_code",
        "label": { "type": "plain_text", "text": "顧客匿名コード" },
        "element": { "type": "plain_text_input", "action_id": "value", "placeholder": { "type": "plain_text", "text": "例: CUST-A" } }
      },
      {
        "type": "input", "block_id": "feedback_type",
        "label": { "type": "plain_text", "text": "フィードバック区分" },
        "element": {
          "type": "static_select", "action_id": "value",
          "placeholder": { "type": "plain_text", "text": "選択" },
          "options": [
            { "text": { "type": "plain_text", "text": "満足" }, "value": "satisfaction" },
            { "text": { "type": "plain_text", "text": "不満・クレーム" }, "value": "complaint" },
            { "text": { "type": "plain_text", "text": "トラブル発生" }, "value": "trouble" },
            { "text": { "type": "plain_text", "text": "紹介意向あり" }, "value": "referral" },
            { "text": { "type": "plain_text", "text": "追加購入意向" }, "value": "repeat" }
          ]
        }
      },
      {
        "type": "input", "block_id": "rating",
        "label": { "type": "plain_text", "text": "満足度（1-5）" },
        "element": {
          "type": "static_select", "action_id": "value",
          "options": [
            { "text": { "type": "plain_text", "text": "★☆☆☆☆ (1)" }, "value": "1" },
            { "text": { "type": "plain_text", "text": "★★☆☆☆ (2)" }, "value": "2" },
            { "text": { "type": "plain_text", "text": "★★★☆☆ (3)" }, "value": "3" },
            { "text": { "type": "plain_text", "text": "★★★★☆ (4)" }, "value": "4" },
            { "text": { "type": "plain_text", "text": "★★★★★ (5)" }, "value": "5" }
          ]
        }
      },
      {
        "type": "input", "block_id": "content",
        "label": { "type": "plain_text", "text": "具体的なフィードバック" },
        "element": { "type": "plain_text_input", "action_id": "value", "multiline": true }
      },
      {
        "type": "input", "block_id": "action_needed",
        "label": { "type": "plain_text", "text": "対応が必要な事項" },
        "element": { "type": "plain_text_input", "action_id": "value", "multiline": true },
        "optional": true
      }
    ]
  }
}
